import{_ as a,o as i,c as n,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Iluminación de Seguridad y Emergencia","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-practices/lighting/safety-emergency-lighting.md","filePath":"es/industrial-practices/lighting/safety-emergency-lighting.md"}'),s={name:"es/industrial-practices/lighting/safety-emergency-lighting.md"};function l(c,e,o,d,t,u){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="iluminacion-de-seguridad-y-emergencia" tabindex="-1">Iluminación de Seguridad y Emergencia <a class="header-anchor" href="#iluminacion-de-seguridad-y-emergencia" aria-label="Permalink to &quot;Iluminación de Seguridad y Emergencia&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La iluminación de seguridad y emergencia proporciona iluminación durante condiciones anormales como fallas de energía, averías o situaciones peligrosas.</p><p>Estos sistemas aseguran que las áreas críticas permanezcan visibles, permitiendo una evacuación segura, parada o intervención cuando la iluminación normal no está disponible.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la iluminación de seguridad y emergencia es mantener la visibilidad en situaciones donde la operación normal se interrumpe.</p><p>Esto ayuda a:</p><ul><li>Permitir la evacuación segura del personal</li><li>Prevenir accidentes durante pérdida de energía</li><li>Apoyar acciones de respuesta de emergencia</li><li>Mantener la visibilidad de equipo crítico y vías de acceso</li></ul><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los sistemas de iluminación de emergencia están diseñados para operar independientemente de la iluminación normal.</p><p>Típicamente incluyen:</p><ul><li>Fuentes de energía de respaldo como baterías o sistemas de emergencia centralizados</li><li>Activación automática cuando se pierde la energía normal</li><li>Luminarias dedicadas o funciones de emergencia integradas en luminarias estándar</li></ul><p>Los tipos comunes de iluminación de emergencia incluyen:</p><ul><li>Iluminación de rutas de escape para vías de acceso y salidas</li><li>Iluminación de área abierta para prevenir pánico en espacios grandes</li><li>Iluminación de áreas de tarea de alto riesgo para operaciones críticas</li></ul><p>Estos sistemas deben proporcionar iluminación suficiente durante un período definido.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La iluminación de seguridad y emergencia se utiliza en:</p><ul><li>Instalaciones industriales y plantas de manufactura</li><li>Salas de control y áreas eléctricas</li><li>Almacenes e instalaciones de almacenamiento</li><li>Espacios de acceso público y ocupados</li><li>Áreas con operaciones peligrosas</li></ul><p>Son esenciales dondequiera que la pérdida de iluminación pueda crear riesgo.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>La iluminación de emergencia debe activarse automática y confiablemente</li><li>Los niveles de iluminación deben ser suficientes para un movimiento seguro</li><li>La duración de la energía de respaldo debe cumplir los requisitos operativos</li><li>El sistema debe probarse y mantenerse regularmente</li><li>La colocación debe cubrir rutas de escape y áreas críticas</li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La falta de iluminación de emergencia crea riesgos graves de seguridad durante cortes de energía</li><li>Los sistemas de batería se degradan con el tiempo y requieren reemplazo periódico</li><li>Las luminarias de emergencia deben ser claramente identificables</li><li>Las pruebas deben ser parte de los procedimientos rutinarios de mantenimiento</li><li>Asegúrese de que la iluminación de emergencia no esté obstruida por equipo o cambios de disposición</li></ul>',23)])])}const g=a(s,[["render",l]]);export{m as __pageData,g as default};
